using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1) Get strongly-typed metadata: JsonTypeInfo<Person>
JsonTypeInfo<Person> personInfo = (JsonTypeInfo<Person>)options.GetTypeInfo(typeof(Person));
Console.WriteLine($"Typed metadata for Person: {personInfo.Type.Name}, Kind={personInfo.Kind}");

// Serialize using the typed metadata directly
string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2) Probe without throwing using TryGetTypeInfo
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? found))
{
    Console.WriteLine($"\nTryGetTypeInfo(Person) succeeded: {found!.Type.Name}");
}

// Now probe for a type that has NO metadata (use a resolver that only handles Person)
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(new PersonOnlyResolver())
};

if (limited.TryGetTypeInfo(typeof(int), out JsonTypeInfo? intInfo))
{
    Console.WriteLine($"Found int metadata: {intInfo!.Type.Name}");
}
else
{
    Console.WriteLine("\nTryGetTypeInfo(int) returned false — no metadata available, no exception thrown.");
}

record Person(string Name, int Age);

// A resolver that only knows about Person
file class PersonOnlyResolver : IJsonTypeInfoResolver
{
    public JsonTypeInfo? GetTypeInfo(Type type, JsonSerializerOptions options)
    {
        if (type == typeof(Person))
        {
            var info = JsonTypeInfo.CreateJsonTypeInfo<Person>(options);
            info.CreateObject = () => new Person("", 0);
            return info;
        }
        return null; // signal "I don't handle this type"
    }
}

